1	// claim-office.ts
2	
3	type Customer = { yearsWithMHPCO: number; previousContracts?: number };
4	type ItemType = "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
5	type Item = {
6	  type: ItemType;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	};
11	
12	export type Damage = { itemType: ItemType; amount: number };
13	export type Incident = { cause: string; damages: Damage[] };
14	export type Policy = { items: Item[]; cap: number; remainingCap: number };
15	export type ClaimResult = { payout: number; remainingCap: number };
16	
17	const PROCESSING_FEE = 5;
18	const INSURANCE_SURCHARGE_RATE = 0.1;
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_PRICE = 60;
21	const CURSE_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
24	const LOYALTY_THRESHOLD_YEARS = 2;
25	const LOYALTY_DISCOUNT_RATE = 0.2;
26	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
27	
28	const BASE_PREMIUMS: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	
39	function itemSurchargeRate(item: Item): number {
40	  const curseRate = item.cursed ? CURSE_SURCHARGE_RATE : 0;
41	  const highEnchantmentRate =
42	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
43	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
44	      : 0;
45	  return curseRate + highEnchantmentRate;
46	}
47	
48	function itemSurcharge(item: Item): number {
49	  return BASE_PREMIUMS[item.type] * itemSurchargeRate(item);
50	}
51	
52	function componentBlockPremium(count: number, unitPrice: number): number {
53	  return count === COMPONENT_BLOCK_SIZE
54	    ? COMPONENT_BLOCK_PRICE
55	    : count * unitPrice;
56	}
57	
58	// Sum of item base premiums (with component block discount applied,
59	// but without item-level surcharges).
60	function policyBasePremium(items: Item[]): number {
61	  const componentCounts: Record<string, number> = {};
62	  let nonComponentBase = 0;
63	  for (const item of items) {
64	    if (COMPONENT_TYPES.has(item.type)) {
65	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
66	    } else {
67	      nonComponentBase += BASE_PREMIUMS[item.type];
68	    }
69	  }
70	  const componentBase = Object.entries(componentCounts).reduce(
71	    (total, [type, count]) =>
72	      total + componentBlockPremium(count, BASE_PREMIUMS[type]),
73	    0
74	  );
75	  return nonComponentBase + componentBase;
76	}
77	
78	function totalItemSurcharges(items: Item[]): number {
79	  return items
80	    .filter((i) => !COMPONENT_TYPES.has(i.type))
81	    .reduce((total, item) => total + itemSurcharge(item), 0);
82	}
83	
84	const INSURANCE_VALUES: Record<string, number> = {
85	  sword: 1000,
86	  amulet: 600,
87	  staff: 800,
88	  potion: 400,
89	  rune: 250,
90	  moonstone: 250,
91	};
92	
93	const DEDUCTIBLE = 100;
94	const CAP_MULTIPLIER = 2;
95	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
96	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
97	const DRAGON_MATERIAL = "dragon";
98	
99	export function createPolicy(items: Item[]): Policy {
100	  const insuranceSum = items.reduce(
101	    (total, item) => total + INSURANCE_VALUES[item.type],
102	    0
103	  );
104	  const cap = insuranceSum * CAP_MULTIPLIER;
105	  return { items, cap, remainingCap: cap };
106	}
107	
108	function findMatchingItem(items: Item[], itemType: ItemType, used: Set<number>): Item | undefined {
109	  for (let i = 0; i < items.length; i++) {
110	    if (!used.has(i) && items[i].type === itemType) {
111	      used.add(i);
112	      return items[i];
113	    }
114	  }
115	  return undefined;
116	}
117	
118	function reimbursementForItem(item: Item, damageAmount: number): number {
119	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
120	    return damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
121	  }
122	  if (item.material === DRAGON_MATERIAL) {
123	    return damageAmount;
124	  }
125	  return damageAmount;
126	}
127	
128	export function claim(policy: Policy, incident: Incident): ClaimResult {
129	  const used = new Set<number>();
130	  let totalPayout = 0;
131	  for (const damage of incident.damages) {
132	    if (damage.amount < 0) {
133	      throw new Error(`negative damage amount: ${damage.amount}`);
134	    }
135	    const item = findMatchingItem(policy.items, damage.itemType, used);
136	    if (!item) {
137	      throw new Error(`damage references item not in policy: ${damage.itemType}`);
138	    }
139	    const reimbursement = reimbursementForItem(item, damage.amount);
140	    const afterDeductible = Math.max(0, reimbursement - DEDUCTIBLE);
141	    totalPayout += afterDeductible;
142	  }
143	  const cappedPayout = Math.min(totalPayout, policy.remainingCap);
144	  const finalPayout = Math.floor(cappedPayout);
145	  policy.remainingCap -= finalPayout;
146	  return { payout: finalPayout, remainingCap: policy.remainingCap };
147	}
148	
149	export function quote(customer: Customer, items: Item[]): number {
150	  for (const item of items) {
151	    if (!(item.type in BASE_PREMIUMS)) {
152	      throw new Error(`unknown item type: ${item.type}`);
153	    }
154	  }
155	  const policyBase = policyBasePremium(items);
156	  const itemSurcharges = totalItemSurcharges(items);
157	  const insuranceSurcharge = policyBase * INSURANCE_SURCHARGE_RATE;
158	  const loyaltyDiscount =
159	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
160	      ? policyBase * LOYALTY_DISCOUNT_RATE
161	      : 0;
162	  const followUpDiscount =
163	    (customer.previousContracts ?? 0) > 0
164	      ? policyBase * FOLLOW_UP_DISCOUNT_RATE
165	      : 0;
166	  return Math.ceil(
167	    policyBase
168	      + itemSurcharges
169	      + insuranceSurcharge
170	      - loyaltyDiscount
171	      - followUpDiscount
172	      + PROCESSING_FEE
173	  );
174	}
